                {'id': 'route-default', 'guild_id': 1, 'channel_id': None, 'platform': 'twitter', 'enabled': True, 'route_config': {'name': 'default'}},
            ],
        }
    def table(self, name):
        return FakeQuery(self.tables.get(name, []))

